<script>
document.addEventListener('DOMContentLoaded', () => {
    // BA Slider logic
    const baSliders = document.querySelectorAll('.ba-container');
    
    baSliders.forEach(slider => {
        const overImg = slider.querySelector('.ba-img.over');
        const handle = slider.querySelector('.ba-handle-new');
        
        if (overImg && handle) {
            const move = (e) => {
                const rect = slider.getBoundingClientRect();
                let x = (e.pageX || e.touches[0].pageX) - rect.left - window.scrollX;
                if (x < 0) x = 0;
                if (x > rect.width) x = rect.width;
                const percent = (x / rect.width) * 100;
                overImg.style.clipPath = `inset(0 ${100 - percent}% 0 0)`;
                handle.style.left = `${percent}%`;
            };
            
            slider.addEventListener('mousemove', move);
            slider.addEventListener('touchmove', move);
        }
    });
});
</script>

<!-- Подключаем API Яндекс Карт -->
<!-- В идеале получите свой API ключ в кабинете разработчика Яндекса и вставьте вместо "ваш_api_ключ" -->
<script src="https://api-maps.yandex.ru/2.1/?apikey=496cd84c-0a7a-4b7e-a9d5-bd9261e5f0a6&lang=ru_RU" type="text/javascript"></script>

<script>
document.addEventListener('DOMContentLoaded', function () {
    // Ждем загрузки API Яндекса
    ymaps.ready(init);

    function init() {
        // Координаты вашего офиса (пр. Металлистов д. 19/30)
        // Примерные координаты, замените на точные
        var centerCoords = [59.957545, 30.412431]; 

        // Создаем карту
        var myMap = new ymaps.Map('yandex-map', {
            center: centerCoords,
            zoom: 17, // Чуть ближе к метке
            controls: ['zoomControl'] // Оставляем только зум
        });

        // Отключаем скролл колесиком (чтобы страница не застревала на карте)
        myMap.behaviors.disable('scrollZoom');

        // Создаем кастомный HTML-макет (шаблон) для нашего балуна (карточки)
        var MyBalloonLayout = ymaps.templateLayoutFactory.createClass(
            '<div class="map-custom-card">' +
                '<h3 class="m-card-title">Спецуборка — офис</h3>' +
                '<p class="m-card-address">Санкт-Петербург, пр. Металлистов д. 19/30</p>' +
                '<p class="m-card-phone">Тел: <a href="tel:+78129007868">+7 (812) 900-78-68</a></p>' +
                '<span class="m-card-badge">Выезд по СПб и ЛенОбласти</span>' +
                '<div class="m-card-actions">' +
                    // Замените ссылку на реальную ссылку маршрута в Яндекс Картах
                    '<a href="https://yandex.ru/maps/-/CD..." target="_blank" class="btn-map btn-map-solid">Маршрут</a>' +
                    '<a href="tel:+78129007868" class="btn-map btn-map-outline">Позвонить</a>' +
                '</div>' +
            '</div>'
        );

        var pinGapPx = window.innerWidth <= 768 ? 8 : 10;
        var myPlacemark;

        function syncBalloonOffsetFromDom() {
            var el = document.querySelector('#yandex-map .map-custom-card');
            if (!el || !myPlacemark) {
                return;
            }
            var rect = el.getBoundingClientRect();
            var w = rect.width;
            var h = rect.height;
            /* Родитель балуна иногда отдаёт схлопнутую ширину на первом кадре — не доверять min(100%,…) */
            if (w < 120) {
                w = Math.min(245, Math.max(196, Math.round(196 + (window.innerWidth - 360) * 0.12)));
            }
            if (h < 2) {
                return;
            }
            myPlacemark.options.set('balloonOffset', [
                -Math.round(w / 2),
                -Math.round(h + pinGapPx)
            ]);
        }

        myPlacemark = new ymaps.Placemark(centerCoords, {
            // Данные метки (не обязательны, так как шаблон жестко прописан, но можно передавать переменные)
        }, {
            balloonLayout: MyBalloonLayout,
            balloonCloseButton: false,
            balloonPanelMaxMapArea: 0,
            hideIconOnBalloonOpen: false,
            balloonOffset: [0, 0]
        });

        myPlacemark.events.add('balloonopen', function () {
            requestAnimationFrame(function () {
                requestAnimationFrame(syncBalloonOffsetFromDom);
            });
            setTimeout(syncBalloonOffsetFromDom, 120);
        });

        var balloonResizeTimer;
        window.addEventListener('resize', function () {
            clearTimeout(balloonResizeTimer);
            balloonResizeTimer = setTimeout(function () {
                if (!myPlacemark || !myPlacemark.balloon.isOpen()) {
                    return;
                }
                pinGapPx = window.innerWidth <= 768 ? 8 : 10;
                syncBalloonOffsetFromDom();
            }, 150);
        });

        myMap.geoObjects.add(myPlacemark);
        myPlacemark.balloon.open();
    }
});
</script>

<script>
document.addEventListener('DOMContentLoaded', () => {
    const faqItems = document.querySelectorAll('.faq-item');

    // Функция для инициализации (чтобы открытый по умолчанию блок сразу получил правильную высоту)
    const initFaq = () => {
        faqItems.forEach(item => {
            if (item.classList.contains('active')) {
                const answer = item.querySelector('.faq-answer');
                answer.style.maxHeight = answer.scrollHeight + "px";
            }
        });
    }
    
    // Запускаем инициализацию при загрузке
    initFaq();

    // Обработчик кликов
    faqItems.forEach(item => {
        const questionBtn = item.querySelector('.faq-question');
        
        questionBtn.addEventListener('click', () => {
            const isActive = item.classList.contains('active');
            
            // Сначала закрываем все открытые вопросы (опционально, но так красивее)
            faqItems.forEach(otherItem => {
                otherItem.classList.remove('active');
                otherItem.querySelector('.faq-answer').style.maxHeight = 0;
            });

            // Если кликнули по закрытому — открываем
            if (!isActive) {
                item.classList.add('active');
                const answer = item.querySelector('.faq-answer');
                answer.style.maxHeight = answer.scrollHeight + "px";
            }
        });
    });
    
    // Пересчет высоты при ресайзе окна (чтобы текст не обрезался, если пользователь повернет телефон)
    window.addEventListener('resize', () => {
        initFaq();
    });
});
</script>

<script>// Починка слайдера До/После
const initComparisonSlider = () => {
    const container = document.querySelector('.comparison-container');
    const afterBox = document.querySelector('.img-after');
    const divider = document.querySelector('.comparison-divider');

    if (!container || !afterBox || !divider) return;

    const moveSlider = (e) => {
        // Определяем X координату (мышь или тач)
        let x = e.type.includes('touch') ? e.touches[0].pageX : e.pageX;
        
        let rect = container.getBoundingClientRect();
        let position = x - rect.left;

        // Ограничители, чтобы не выходить за края
        if (position < 0) position = 0;
        if (position > rect.width) position = rect.width;

        let percent = (position / rect.width) * 100;

        // Двигаем "После" и ползунок
        afterBox.style.width = percent + '%';
        divider.style.left = percent + '%';
    };

    // Слушатели для мышки
    container.addEventListener('mousemove', moveSlider);
    // Слушатели для мобилок
    container.addEventListener('touchmove', moveSlider);
};

// Запуск после загрузки страницы
document.addEventListener('DOMContentLoaded', initComparisonSlider);
</script>

<script>
document.addEventListener('DOMContentLoaded', () => {
    const navLinks = document.querySelectorAll('.g-nav-link');
    const tabContents = document.querySelectorAll('.g-tab-content');

    tabContents.forEach((tab, index) => {
        const step = String(index + 1).padStart(2, '0');
        tab.setAttribute('data-step', step);
        const title = tab.querySelector('h3');
        if (title) {
            title.setAttribute('data-step', step);
        }
    });

    navLinks.forEach(link => {
        link.addEventListener('click', (e) => {
            e.preventDefault(); // Чтобы страница не прыгала вверх

            const targetId = link.getAttribute('data-target');

            // 1. Убираем активный класс у всех ссылок
            navLinks.forEach(l => l.classList.remove('active'));
            // 2. Убираем активный класс у всех блоков текста
            tabContents.forEach(c => c.classList.remove('active'));

            // 3. Добавляем активный класс текущей ссылке
            link.classList.add('active');
            // 4. Показываем нужный блок текста
            document.getElementById(targetId).classList.add('active');
        });
    });
});</script>
<script>
document.addEventListener('DOMContentLoaded', () => {
    const track = document.querySelector('.reviews-grid-new');
    const sliderWindow = document.querySelector('.reviews-slider-window');
    const cards = document.querySelectorAll('.review-card-item');
    const nextBtn = document.querySelector('.nav-arrow.next');
    const prevBtn = document.querySelector('.nav-arrow.prev');
    const mobileIndicator = document.getElementById('reviews-mobile-indicator');

    if (!track || !sliderWindow || cards.length === 0 || !nextBtn || !prevBtn) return;

    let currentIndex = 0;

    const renderMobileDots = () => {
        if (!mobileIndicator) return;
        mobileIndicator.innerHTML = '';
        cards.forEach((_, i) => {
            const dot = document.createElement('span');
            dot.className = 'reviews-mobile-indicator__dot' + (i === 0 ? ' is-active' : '');
            mobileIndicator.appendChild(dot);
        });
    };

    const updateMobileDots = () => {
        if (!mobileIndicator) return;
        const dots = mobileIndicator.querySelectorAll('.reviews-mobile-indicator__dot');
        if (!dots.length) return;
        let active = 0;
        let minDelta = Infinity;
        const windowRect = sliderWindow.getBoundingClientRect();
        cards.forEach((card, index) => {
            const rect = card.getBoundingClientRect();
            const delta = Math.abs(rect.left - windowRect.left);
            if (delta < minDelta) {
                minDelta = delta;
                active = index;
            }
        });
        dots.forEach((dot, i) => dot.classList.toggle('is-active', i === active));
    };

    function updateSlider() {
        if (window.innerWidth <= 700) {
            track.style.transform = 'none';
            updateMobileDots();
            return;
        }

        let visibleCards = 3;
        if (window.innerWidth <= 1024) visibleCards = 2;
        if (window.innerWidth <= 768) visibleCards = 1;

        const maxIndex = Math.max(0, cards.length - visibleCards);

        if (currentIndex > maxIndex) currentIndex = maxIndex;
        if (currentIndex < 0) currentIndex = 0;

        const card = cards[currentIndex];
        const offsetX = card ? Math.round(card.offsetLeft) : 0;
        track.style.transform = 'translateX(-' + offsetX + 'px)';

        prevBtn.style.opacity = (currentIndex === 0) ? '0.3' : '1';
        prevBtn.style.pointerEvents = (currentIndex === 0) ? 'none' : 'auto';

        nextBtn.style.opacity = (currentIndex >= maxIndex) ? '0.3' : '1';
        nextBtn.style.pointerEvents = (currentIndex >= maxIndex) ? 'none' : 'auto';
    }

    nextBtn.addEventListener('click', () => {
        currentIndex++;
        updateSlider();
    });

    prevBtn.addEventListener('click', () => {
        currentIndex--;
        updateSlider();
    });

    sliderWindow.addEventListener('scroll', () => {
        if (window.innerWidth <= 700) {
            updateMobileDots();
        }
    }, { passive: true });

    renderMobileDots();
    window.addEventListener('resize', updateSlider);
    updateSlider();
});
</script>

<script>
    document.addEventListener('DOMContentLoaded', () => {
    const districtCards = document.querySelectorAll('.district-card');
    const highlightBox = document.querySelector('.info-highlight-box p');

    if (!highlightBox || districtCards.length === 0) return;

    districtCards.forEach(card => {
        card.addEventListener('click', () => {
            // 1. Убираем активный класс у всех и добавляем текущей
            districtCards.forEach(c => c.classList.remove('active'));
            card.classList.add('active');

            // 2. Берем данные из атрибутов кликнутой карточки
            const name = card.getAttribute('data-name');
            const desc = card.getAttribute('data-desc');
            const time = card.getAttribute('data-time');

            // 3. Обновляем текст в цветном блоке (info-highlight-box)
            highlightBox.innerHTML = `<strong>${name} район</strong> — ${desc} <span class="text-blue fw-700">Время выезда: ${time}</span>`;
        });
    });
});
</script>
<?php get_footer(); ?>

